        setContentView(R.layout.activity_main); // Assuming you have an activity_main.xml with a WebView

        webView = findViewById(R.id.webView); // Assuming your WebView has id="webView" in activity_main.xml

        WebSettings webSettings = webView.getSettings();
        webSettings.setJavaScriptEnabled(true); // Enable JavaScript
        webSettings.setDomStorageEnabled(true); // Enable DOM storage (localStorage, sessionStorage)
        webSettings.setDatabaseEnabled(true); // Enable database storage (Web SQL Database API)
        webSettings.setAllowFileAccess(true); // Allow access to file URLs
        webSettings.setJavaScriptCanOpenWindowsAutomatically(true); // Allow JavaScript to open new windows
        webSettings.setSupportMultipleWindows(true); // Support multiple windows (e.g., pop-ups)
        webSettings.setLoadWithOverviewMode(true); // Zoom out if the content is too big
        webSettings.setUseWideViewPort(true); // Make the WebView behave like a desktop browser

        // Add the JavaScript interface
